#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


uv1 = (vUv-.5)*uAspect.xy*tele;
dist = .6;
float z = clamp(abs(1/(uv1.y)),0,12);
uv1 = vec2 (uv1.x*z,z*.4);
uv2 = multiply(vec3(uv1*dist,dist-.0),RotMat)+CamPos;
uv2 = (fract(uv2/8.0+.5)-.5)*8.0;
box = mbox (uv2);
struc2 = length(box.xy)/12;


ret.r = clamp01(struc2*.01) * (length(box) > q30);

ret.b = max(GetPixel((vUvOriginal-.5)*1.04+.5).b*.97,ret.r);



  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

float tele = q16;
vec2 uv0 = vUv;
vUv = vec2(abs(vUv.x-.5)+.5,vUv.y);
vUv = abs(vUv-.5)+.5;
vec3   ret2 = texture(sampler_main,vUv).xyz;

float blur1 = lum(GetBlur2(vUv));
ret2 *= (.6+.5*sin(vUv.x*10+uTime));
ret2= mix(blur1,ret2,pow(ret2,.05+(audioMidSmooth)*.050));

vec2 uv1 = vUv-.5;
vec3 ret1 = texture(sampler_main, vUv) ;

const vec2 hor = vec2 (.001,0);
const vec2 ver = vec2 (0,.001);

float dx = GetPixel (vUv-hor).r - GetPixel (vUv+hor).r;
float dy = GetPixel (vUv-ver).r - GetPixel (vUv+ver).r;
vec2 dz = vec2 (dx,dy);

dz += abs(texture(sampler_noise_hq,uv1/(-.1/tele+vRadius)*q22*q23+q31)-.5)*.1;

uv1 = uv1 -4*dz;
float dots = clamp01(.02/length(uv1));

ret1 = 0.3*lum(ret1)+dots*ret2*(6+audioMid*3);
ret = ret1;

uv1 = vUv-.5 + .4*GetPixel(vUv).rb ;
ret += exp(-20*(length(fract((uv1.x)*3-uTime)-.5)))*q10 ;

//ret = GetPixel(vUv);

  fragColor = ret;
}
